<template>
  <div class="admin-list-container">
    <el-card>
      <div slot="header" class="clearfix">
        <span>管理员列表</span>
        <el-button
          style="float: right; padding: 3px 0"
          type="text"
          icon="el-icon-plus"
          @click="handleAdd">
          添加管理员
        </el-button>
      </div>
      
      <!-- 搜索表单 -->
      <el-form :inline="true" :model="searchForm" class="search-form">
        <el-form-item label="用户名">
          <el-input v-model="searchForm.username" placeholder="请输入用户名" clearable></el-input>
        </el-form-item>
        <el-form-item label="手机号">
          <el-input v-model="searchForm.phone" placeholder="请输入手机号" clearable></el-input>
        </el-form-item>
        <el-form-item label="状态">
          <el-select v-model="searchForm.status" placeholder="全部" clearable>
            <el-option label="启用" :value="1"></el-option>
            <el-option label="禁用" :value="0"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="handleSearch">查询</el-button>
          <el-button @click="resetSearch">重置</el-button>
        </el-form-item>
      </el-form>
      
      <!-- 管理员列表 -->
      <el-table
        :data="adminList"
        style="width: 100%"
        border
        v-loading="loading">
        <el-table-column
          type="index"
          label="序号"
          width="60"
          align="center">
        </el-table-column>
        <el-table-column
          prop="username"
          label="用户名"
          width="120">
        </el-table-column>
        <el-table-column
          prop="name"
          label="姓名"
          width="120">
        </el-table-column>
        <el-table-column
          prop="phone"
          label="手机号"
          width="120">
        </el-table-column>
        <el-table-column
          prop="email"
          label="邮箱"
          width="180">
        </el-table-column>
        <el-table-column
          prop="roleName"
          label="角色"
          width="120">
        </el-table-column>
        <el-table-column
          prop="status"
          label="状态"
          width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status === 1 ? 'success' : 'info'">
              {{ scope.row.status === 1 ? '启用' : '禁用' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column
          prop="lastLoginTime"
          label="最后登录时间"
          width="180">
        </el-table-column>
        <el-table-column
          prop="createTime"
          label="创建时间"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作"
          fixed="right"
          width="200">
          <template slot-scope="scope">
            <el-button
              @click="handleEdit(scope.row)"
              type="text"
              size="small">
              编辑
            </el-button>
            <el-button
              @click="handleResetPassword(scope.row)"
              type="text"
              size="small">
              重置密码
            </el-button>
            <el-button
              v-if="scope.row.status === 1"
              @click="handleStatusChange(scope.row, 0)"
              type="text"
              size="small">
              禁用
            </el-button>
            <el-button
              v-else
              @click="handleStatusChange(scope.row, 1)"
              type="text"
              size="small">
              启用
            </el-button>
            <el-button
              v-if="scope.row.username !== 'admin'"
              @click="handleDelete(scope.row)"
              type="text"
              size="small"
              class="danger-btn">
              删除
            </el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!loading && adminList.length === 0" description="暂无数据" />
      
      <!-- 分页 -->
      <div class="pagination-container">
        <el-pagination
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="pagination.currentPage"
          :page-sizes="[10, 20, 50, 100]"
          :page-size="pagination.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="pagination.total">
        </el-pagination>
      </div>
    </el-card>
    
    <!-- 添加/编辑管理员对话框 -->
    <el-dialog :title="dialogStatus === 'create' ? '添加管理员' : '编辑管理员'" :visible.sync="dialogVisible" width="500px">
      <el-form
        ref="adminForm"
        :model="adminForm"
        :rules="adminRules"
        label-width="100px"
        class="admin-form">
        <el-form-item label="用户名" prop="username">
          <el-input v-model="adminForm.username" :disabled="dialogStatus === 'update'"></el-input>
        </el-form-item>
        <el-form-item label="姓名" prop="name">
          <el-input v-model="adminForm.name"></el-input>
        </el-form-item>
        <el-form-item label="手机号" prop="phone">
          <el-input v-model="adminForm.phone"></el-input>
        </el-form-item>
        <el-form-item label="邮箱" prop="email">
          <el-input v-model="adminForm.email"></el-input>
        </el-form-item>
        <el-form-item v-if="dialogStatus === 'create'" label="密码" prop="password">
          <el-input v-model="adminForm.password" type="password" show-password></el-input>
        </el-form-item>
        <el-form-item v-if="dialogStatus === 'create'" label="确认密码" prop="confirmPassword">
          <el-input v-model="adminForm.confirmPassword" type="password" show-password></el-input>
        </el-form-item>
        <el-form-item label="角色" prop="roleId">
          <el-select v-model="adminForm.roleId" placeholder="请选择角色">
            <el-option
              v-for="item in roleOptions"
              :key="item.id"
              :label="item.name"
              :value="item.id">
            </el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="状态" prop="status">
          <el-switch
            v-model="adminForm.status"
            :active-value="1"
            :inactive-value="0"
            active-text="启用"
            inactive-text="禁用">
          </el-switch>
        </el-form-item>
        <el-form-item label="备注" prop="remark">
          <el-input
            type="textarea"
            :rows="3"
            placeholder="请输入备注"
            v-model="adminForm.remark">
          </el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">取 消</el-button>
        <el-button type="primary" @click="submitForm" :loading="submitLoading">确 定</el-button>
      </div>
    </el-dialog>
    
    <!-- 重置密码对话框 -->
    <el-dialog title="重置密码" :visible.sync="resetPwdVisible" width="500px">
      <el-form
        ref="resetPwdForm"
        :model="resetPwdForm"
        :rules="resetPwdRules"
        label-width="100px">
        <el-form-item label="新密码" prop="password">
          <el-input v-model="resetPwdForm.password" type="password" show-password></el-input>
        </el-form-item>
        <el-form-item label="确认密码" prop="confirmPassword">
          <el-input v-model="resetPwdForm.confirmPassword" type="password" show-password></el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="resetPwdVisible = false">取 消</el-button>
        <el-button type="primary" @click="submitResetPwd">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import request from '@/api/index'

export default {
  name: 'AdminList',
  data() {
    // 密码验证规则
    const validatePassword = (rule, value, callback) => {
      if (value.length < 6) {
        callback(new Error('密码不能少于6个字符'))
      } else {
        if (this.adminForm.confirmPassword !== '') {
          this.$refs.adminForm.validateField('confirmPassword')
        }
        callback()
      }
    }
    // 确认密码验证规则
    const validateConfirmPassword = (rule, value, callback) => {
      if (value !== this.adminForm.password) {
        callback(new Error('两次输入密码不一致'))
      } else {
        callback()
      }
    }
    // 重置密码验证规则
    const validateResetPassword = (rule, value, callback) => {
      if (value.length < 6) {
        callback(new Error('密码不能少于6个字符'))
      } else {
        if (this.resetPwdForm.confirmPassword !== '') {
          this.$refs.resetPwdForm.validateField('confirmPassword')
        }
        callback()
      }
    }
    // 重置确认密码验证规则
    const validateResetConfirmPassword = (rule, value, callback) => {
      if (value !== this.resetPwdForm.password) {
        callback(new Error('两次输入密码不一致'))
      } else {
        callback()
      }
    }
    
    return {
      // 搜索表单
      searchForm: {
        username: '',
        phone: '',
        status: ''
      },
      // 管理员列表
      adminList: [],
      // 加载状态
      loading: false,
      submitLoading: false,
      // 分页
      pagination: {
        currentPage: 1,
        pageSize: 10,
        total: 0
      },
      // 对话框状态：create-创建，update-更新
      dialogStatus: 'create',
      // 对话框是否可见
      dialogVisible: false,
      // 管理员表单
      adminForm: {
        id: undefined,
        username: '',
        name: '',
        phone: '',
        email: '',
        password: '',
        confirmPassword: '',
        roleId: '',
        status: 1,
        remark: ''
      },
      // 管理员表单校验规则
      adminRules: {
        username: [
          { required: true, message: '请输入用户名', trigger: 'blur' },
          { min: 3, max: 20, message: '长度在 3 到 20 个字符', trigger: 'blur' }
        ],
        name: [
          { required: true, message: '请输入姓名', trigger: 'blur' }
        ],
        phone: [
          { required: true, message: '请输入手机号', trigger: 'blur' },
          { pattern: /^1[3-9]\d{9}$/, message: '请输入正确的手机号码', trigger: 'blur' }
        ],
        email: [
          { required: true, message: '请输入邮箱', trigger: 'blur' },
          { type: 'email', message: '请输入正确的邮箱地址', trigger: 'blur' }
        ],
        password: [
          { required: true, message: '请输入密码', trigger: 'blur' },
          { validator: validatePassword, trigger: 'blur' }
        ],
        confirmPassword: [
          { required: true, message: '请再次输入密码', trigger: 'blur' },
          { validator: validateConfirmPassword, trigger: 'blur' }
        ],
        roleId: [
          { required: true, message: '请选择角色', trigger: 'change' }
        ]
      },
      // 角色选项
      roleOptions: [
        { id: 1, name: '超级管理员' },
        { id: 2, name: '普通管理员' },
        { id: 3, name: '商品管理员' },
        { id: 4, name: '订单管理员' }
      ],
      // 重置密码对话框是否可见
      resetPwdVisible: false,
      // 当前处理的管理员ID
      currentAdminId: null,
      // 重置密码表单
      resetPwdForm: {
        password: '',
        confirmPassword: ''
      },
      // 重置密码表单校验规则
      resetPwdRules: {
        password: [
          { required: true, message: '请输入新密码', trigger: 'blur' },
          { validator: validateResetPassword, trigger: 'blur' }
        ],
        confirmPassword: [
          { required: true, message: '请再次输入新密码', trigger: 'blur' },
          { validator: validateResetConfirmPassword, trigger: 'blur' }
        ]
      }
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    // 获取管理员列表数据
    fetchData() {
      this.loading = true
      request({
        url: '/api/admin/admins',
        method: 'get',
        params: {
          page: this.pagination.currentPage,
          size: this.pagination.pageSize,
          ...this.searchForm
        }
      }).then(res => {
        if (res.code === 0) {
          this.adminList = res.data.list || []
          this.pagination.total = res.data.total || 0
        } else {
          this.$message.error(res.message || '获取管理员列表失败')
        }
        this.loading = false
      }).catch(() => {
        this.$message.error('获取管理员列表失败')
        this.adminList = []
        this.pagination.total = 0
        this.loading = false
      })
    },
    // 搜索
    handleSearch() {
      this.pagination.currentPage = 1
      this.fetchData()
    },
    // 重置搜索
    resetSearch() {
      this.searchForm = {
        username: '',
        phone: '',
        status: ''
      }
      this.handleSearch()
    },
    // 改变每页展示数量
    handleSizeChange(val) {
      this.pagination.pageSize = val
      this.fetchData()
    },
    // 改变页码
    handleCurrentChange(val) {
      this.pagination.currentPage = val
      this.fetchData()
    },
    // 添加管理员
    handleAdd() {
      this.resetForm()
      this.dialogStatus = 'create'
      this.dialogVisible = true
      this.$nextTick(() => {
        this.$refs.adminForm && this.$refs.adminForm.clearValidate()
      })
    },
    // 编辑管理员
    handleEdit(row) {
      this.resetForm()
      this.dialogStatus = 'update'
      this.adminForm = {
        id: row.id,
        username: row.username,
        name: row.name,
        phone: row.phone,
        email: row.email,
        roleId: row.roleId,
        status: row.status,
        remark: row.remark
      }
      this.dialogVisible = true
      this.$nextTick(() => {
        this.$refs.adminForm && this.$refs.adminForm.clearValidate()
      })
    },
    // 重置密码
    handleResetPassword(row) {
      this.currentAdminId = row.id
      this.resetPwdForm = {
        password: '',
        confirmPassword: ''
      }
      this.resetPwdVisible = true
      this.$nextTick(() => {
        this.$refs.resetPwdForm && this.$refs.resetPwdForm.clearValidate()
      })
    },
    // 更改状态
    handleStatusChange(row, status) {
      const statusText = status === 1 ? '启用' : '禁用'
      this.$confirm(`确认要${statusText}该管理员吗?`, '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        request({
          url: `/api/admin/admins/${row.id}/status`,
          method: 'put',
          data: { status }
        }).then(res => {
          if (res.code === 0) {
            this.$message.success(`${statusText}成功`)
            this.fetchData()
          } else {
            this.$message.error(res.message || `${statusText}失败`)
          }
        }).catch(() => this.$message.error(`${statusText}失败`))
      }).catch(() => {})
    },
    // 删除管理员
    handleDelete(row) {
      this.$confirm('确认要删除该管理员吗? 删除后不可恢复!', '警告', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        request({
          url: `/api/admin/admins/${row.id}`,
          method: 'delete'
        }).then(res => {
          if (res.code === 0) {
            this.$message.success('删除成功')
            this.fetchData()
          } else {
            this.$message.error(res.message || '删除失败')
          }
        }).catch(() => this.$message.error('删除失败'))
      }).catch(() => {})
    },
    // 重置表单
    resetForm() {
      this.adminForm = {
        id: undefined,
        username: '',
        name: '',
        phone: '',
        email: '',
        password: '',
        confirmPassword: '',
        roleId: '',
        status: 1,
        remark: ''
      }
    },
    // 提交表单
    submitForm() {
      this.$refs.adminForm.validate(valid => {
        if (valid) {
          const formData = { ...this.adminForm }
          delete formData.confirmPassword
          this.submitLoading = true

          if (this.dialogStatus === 'create') {
            request({ url: '/api/admin/admins', method: 'post', data: formData }).then(res => {
              if (res.code === 0) { this.$message.success('添加成功'); this.dialogVisible = false; this.fetchData() }
              else { this.$message.error(res.message || '添加失败') }
              this.submitLoading = false
            }).catch(() => { this.$message.error('添加失败'); this.submitLoading = false })
          } else {
            request({ url: `/api/admin/admins/${formData.id}`, method: 'put', data: formData }).then(res => {
              if (res.code === 0) { this.$message.success('更新成功'); this.dialogVisible = false; this.fetchData() }
              else { this.$message.error(res.message || '更新失败') }
              this.submitLoading = false
            }).catch(() => { this.$message.error('更新失败'); this.submitLoading = false })
          }
        }
      })
    },
    // 提交重置密码
    submitResetPwd() {
      this.$refs.resetPwdForm.validate(valid => {
        if (valid) {
          request({
            url: `/api/admin/admins/${this.currentAdminId}/reset-password`,
            method: 'put',
            data: { password: this.resetPwdForm.password }
          }).then(res => {
            if (res.code === 0) {
              this.$message.success('密码重置成功')
              this.resetPwdVisible = false
            } else {
              this.$message.error(res.message || '重置失败')
            }
          }).catch(() => this.$message.error('重置失败'))
        }
      })
    },
    // 格式化日期时间
    formatDateTime(date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      const hours = String(date.getHours()).padStart(2, '0')
      const minutes = String(date.getMinutes()).padStart(2, '0')
      const seconds = String(date.getSeconds()).padStart(2, '0')
      
      return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`
    }
  }
}
</script>

<style lang="scss" scoped>
.admin-list-container {
  padding: 20px;
  
  .search-form {
    margin-bottom: 20px;
  }
  
  .pagination-container {
    margin-top: 20px;
    text-align: right;
  }
  
  .danger-btn {
    color: #F56C6C;
  }
  
  .admin-form {
    .el-form-item {
      margin-bottom: 22px;
    }
  }
}
</style> 